/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_penjualan_au_sync_detail_payment` AFTER UPDATE ON `penjualan` FOR EACH ROW BEGIN
