/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `trg_penjualan_detail_bi_sync_payment` BEFORE INSERT ON `penjualan_detail` FOR EACH ROW BEGIN
  DECLARE v_payment_method varchar(50);
  SELECT p.payment_method INTO v_payment_method
  FROM penjualan p
  WHERE p.no_trx = NEW.no_trx
  LIMIT 1;
  IF v_payment_method IS NOT NULL AND v_payment_method <> '' THEN
    SET NEW.status_bayar = v_payment_method;
  END IF;
END */;;
